 11‚Üíinternal sealed interface FormatStructure<in T> {
 12‚Üí    fun parser(): ParserStructure<T>
 13‚Üí    fun formatter(): FormatterStructure<T>
 14‚Üí}
 15‚Üí
 16‚Üíinternal class BasicFormatStructure<in T>(
 17‚Üí    val directive: FieldFormatDirective<T>
 18‚Üí) : NonConcatenatedFormatStructure<T> {
 19‚Üí    override fun toString(): String = "BasicFormatStructure($directive)"
 20‚Üí
 21‚Üí    override fun equals(other: Any?): Boolean = other is BasicFormatStructure<*> && directive == other.directive
 22‚Üí    override fun hashCode(): Int = directive.hashCode()
 23‚Üí
 24‚Üí    override fun parser(): ParserStructure<T> = directive.parser()
 25‚Üí    override fun formatter(): FormatterStructure<T> = directive.formatter()
 26‚Üí}
