 62‚Üíinternal class SignedFormatStructure<in T>(
 63‚Üí    val format: FormatStructure<T>,
 64‚Üí    val withPlusSign: Boolean,
 65‚Üí) : NonConcatenatedFormatStructure<T> {
 66‚Üí
 67‚Üí    private val fieldSigns = basicFormats(format).mapNotNull { it.field.sign }.toSet()
 68‚Üí
 69‚Üí    init {
 70‚Üí        require(fieldSigns.isNotEmpty()) { "Signed format must contain at least one field with a sign" }
 71‚Üí    }
 72‚Üí
 73‚Üí    override fun toString(): String = "SignedFormatStructure($format)"
 74‚Üí
 75‚Üí    override fun equals(other: Any?): Boolean =
 76‚Üí        other is SignedFormatStructure<*> && format == other.format && withPlusSign == other.withPlusSign
 77‚Üí
 78‚Üí    override fun hashCode(): Int = 31 * format.hashCode() + withPlusSign.hashCode()
 79‚Üí
 80‚Üí    override fun parser(): ParserStructure<T> = listOf(
 81‚Üí        ParserStructure(
 82‚Üí            operations = listOf(
 83‚Üí                SignParser(
 84‚Üí                    isNegativeSetter = { value, isNegative ->
 85‚Üí                        for (field in fieldSigns) {
 86‚Üí                            val wasNegative = field.isNegative.getter(value) == true
 87‚Üí                            // TODO: replacing `!=` with `xor` fails on JS
 88‚Üí                            field.isNegative.trySetWithoutReassigning(value, isNegative != wasNegative)
 89‚Üí                        }
 90‚Üí                    },
 91‚Üí                    withPlusSign = withPlusSign,
 92‚Üí                    whatThisExpects = "sign for ${this.fieldSigns}"
 93‚Üí                )
 94‚Üí            ),
 95‚Üí            emptyList()
 96‚Üí        ), format.parser()
 97‚Üí    ).concat()
 98‚Üí
 99‚Üí    override fun formatter(): FormatterStructure<T> {
100‚Üí        val innerFormat = format.formatter()
101‚Üí        fun checkIfAllNegative(value: T): Boolean {
102‚Üí            var seenNonZero = false
103‚Üí            for (check in fieldSigns) {
104‚Üí                when {
105‚Üí                    check.isNegative.getter(value) == true -> seenNonZero = true
106‚Üí                    check.isZero(value) -> continue
107‚Üí                    else -> return false
108‚Üí                }
109‚Üí            }
110‚Üí            return seenNonZero
111‚Üí        }
112‚Üí        return SignedFormatter(
113‚Üí            innerFormat,
114‚Üí            ::checkIfAllNegative,
115‚Üí            withPlusSign
116‚Üí        )
117‚Üí    }
118‚Üí}
