120‚Üíinternal class AlternativesParsingFormatStructure<in T>(
121‚Üí    val mainFormat: FormatStructure<T>,
122‚Üí    val formats: List<FormatStructure<T>>,
123‚Üí) : NonConcatenatedFormatStructure<T> {
124‚Üí    override fun toString(): String = "AlternativesParsing($formats)"
125‚Üí
126‚Üí    override fun equals(other: Any?): Boolean =
127‚Üí        other is AlternativesParsingFormatStructure<*> && mainFormat == other.mainFormat && formats == other.formats
128‚Üí
129‚Üí    override fun hashCode(): Int = 31 * mainFormat.hashCode() + formats.hashCode()
130‚Üí
131‚Üí    override fun parser(): ParserStructure<T> = ParserStructure(operations = emptyList(), followedBy = buildList {
132‚Üí        add(mainFormat.parser())
133‚Üí        for (format in formats) {
134‚Üí            add(format.parser())
135‚Üí        }
136‚Üí    })
137‚Üí
138‚Üí    override fun formatter(): FormatterStructure<T> = mainFormat.formatter()
139‚Üí}
