 28‚Üí            val dates = buildMap<LocalDate, Pair<String, Set<String>>> {
 29‚Üí                put(LocalDate(2008, 7, 5), ("2008${s}07${s}05" to setOf()))
 30‚Üí                put(LocalDate(2007, 12, 31), ("2007${s}12${s}31" to setOf()))
 31‚Üí                put(LocalDate(999, 12, 31), ("0999${s}12${s}31" to setOf()))
 32‚Üí                put(LocalDate(-1, 1, 2), ("-0001${s}01${s}02" to setOf()))
 33‚Üí                put(LocalDate(9999, 12, 31), ("9999${s}12${s}31" to setOf()))
 34‚Üí                put(LocalDate(-9999, 12, 31), ("-9999${s}12${s}31" to setOf()))
 35‚Üí                put(LocalDate(10000, 1, 1), ("+10000${s}01${s}01" to setOf()))
 36‚Üí                put(LocalDate(-10000, 1, 1), ("-10000${s}01${s}01" to setOf()))
 37‚Üí                put(LocalDate(123456, 1, 1), ("+123456${s}01${s}01" to setOf()))
 38‚Üí                put(LocalDate(-123456, 1, 1), ("-123456${s}01${s}01" to setOf()))
 39‚Üí            }
 40‚Üí            test(dates, LocalDate.Format {
 41‚Üí                year()
 42‚Üí                byUnicodePattern("${s}MM${s}dd")
 43‚Üí            })
 44‚Üí            test(dates, LocalDate.Format {
 45‚Üí                year()
 46‚Üí                char(s)
 47‚Üí                monthNumber()
 48‚Üí                char(s)
