 53‚Üí
 54‚Üí    @Test
 55‚Üí    fun testSmallEndianDates() {
 56‚Üí        for (s in listOf('/', '-')) {
 57‚Üí            val dates = buildMap<LocalDate, Pair<String, Set<String>>> {
 58‚Üí                put(LocalDate(2008, 7, 5), ("05${s}07${s}2008" to setOf()))
 59‚Üí                put(LocalDate(2007, 12, 31), ("31${s}12${s}2007" to setOf()))
 60‚Üí                put(LocalDate(999, 12, 31), ("31${s}12${s}0999" to setOf()))
 61‚Üí                put(LocalDate(-1, 1, 2), ("02${s}01${s}-0001" to setOf()))
