import kotlinx.datetime.internal.DecimalFraction

/**
 * Checks if a character is an ASCII digit (0-9).
 */
private fun Char.isAsciiDigit(): Boolean = this in '0'..'9'

/**
 * Converts a string to an Int only if it contains exclusively ASCII digits (0-9).
 * Returns null if the string contains non-ASCII digits or other characters.
 */
private fun String.toAsciiIntOrNull(): Int? {
    if (isEmpty()) return null

    // Check if all characters are ASCII digits
    for (char in this) {
        if (!char.isAsciiDigit()) return null
    }

    // Now we can safely use toIntOrNull since we've verified ASCII digits
    return toIntOrNull()
}"}

