    fun testRejectsNonAsciiDigits() {
        // Test that parsing rejects non-ASCII digits that look like ASCII digits
        // Using Unicode full-width digits and Arabic-Indic digits
        val withNonAsciiDigits = "2Ôºê2ÔºîŸÝŸ©ÔºêÔºñ"  // Mix of ASCII and Unicode digits

        // Should fail to parse because non-ASCII digits should be rejected
        LocalDate.Formats.ISO_BASIC.assertCanNotParse(withNonAsciiDigits)

        // Test with different non-ASCII digit characters
        LocalDate.Formats.ISO_BASIC.assertCanNotParse("ÔºíÔºêÔºíÔºîÔºêÔºôÔºêÔºñ")  // All full-width digits
        LocalDate.Formats.ISO_BASIC.assertCanNotParse("Ÿ¢ŸÝŸ¢Ÿ§ŸÝŸ©ŸÝŸ¶")      // All Arabic-Indic digits

        // Test with ISO format (with separators)
        LocalDate.Formats.ISO.assertCanNotParse("2Ôºê24-Ôºê9-Ôºê6")

        // Ensure normal ASCII digits still work
        val withAsciiDigits = "20240906"
        assertEquals(LocalDate(2024, 9, 6), LocalDate.parse(withAsciiDigits, LocalDate.Formats.ISO_BASIC))

        // Ensure normal ISO format still works
        assertEquals(LocalDate(2024, 9, 6), LocalDate.parse("2024-09-06", LocalDate.Formats.ISO))
